import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.ACTOR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.FISCAAL_JAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.OPSLAAN_NULRESULTATEN_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOONSDATA_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REGUL_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENMODUS_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKEN_FEEDBACK_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.SLEUTEL_TUSSENKOMSTEN;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.TUSSENKOMST_MANAGER_KEY;

public class ResultaatHandlerImp extends AbstractResultaatHandler implements ResultaatHandler {

    protected RekenResultatenService rekenResultatenService;

    private ControleAgendaService controleAgendaService;

    private ControlesRekenResultatenService controlesRekenResultatenService;

    private CheckInhoudingZonderVergoedingen checkInhoudingZonderVergoedingen;

    public ResultaatHandlerImp(
            RekenResultatenService rekenResultatenService, WachtAgendaService wachtAgendaService,
            RegulAgendaService regulAgendaService, ControleAgendaService controleAgendaService,
            ControlesRekenResultatenService controlesRekenResultatenService) {
        super(regulAgendaService, wachtAgendaService);
        this.rekenResultatenService = rekenResultatenService;
        this.controleAgendaService = controleAgendaService;
        this.controlesRekenResultatenService = controlesRekenResultatenService;
        this.checkInhoudingZonderVergoedingen = new CheckInhoudingZonderVergoedingen();
    }

    @Override
    public void verwerkResultaten(Admin admin, RekenContext mainContext) {
        TimeLogContext.getInstance().startTimeLogging("ResultaatHandlerImp.verwerkResultaten");
        RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);
        PersoonsDataManager persoonsDataManager = mainContext.getUnchecked(PERSOONSDATA_MANAGER_KEY);
        RegulManager regulManager = mainContext.getUnchecked(REGUL_MANAGER_KEY);
        Rekenmodus rekenmodus = mainContext.getUnchecked(REKENMODUS_KEY);
        List<RekenHoofd> bestaanden = persoonsDataManager.getBestaandeRekenResultaten(rekenTijd.beginDatum);

        List<RekenHoofd> outputs = vormNieuweRekenHoofden(mainContext);
        checkReguls(mainContext, outputs, bestaanden, regulManager);
        RekenFeedback feedback = mainContext.getUnchecked(REKEN_FEEDBACK_KEY);
        persisteerRekenResultaten(admin, outputs, bestaanden, feedback);
        if (rekenmodus != Rekenmodus.VOORSCHOT && feedback.getAantalRekenHoofden() > 0) {
            doeControles(admin, mainContext);
        }

        TimeLogContext.getInstance().endTimeLogging();
    }

    protected List<RekenHoofd> vormNieuweRekenHoofden(RekenContext mainContext) {
        RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);
        PersoonsDataManager persoonsDataManager = mainContext.getUnchecked(PERSOONSDATA_MANAGER_KEY);
        List<RekenHoofd> bestaanden = persoonsDataManager.getBestaandeRekenResultaten(rekenTijd.beginDatum);
        List<RekenHoofd> gelockten = bestaanden.stream().filter(t -> t.getRnummer() != null).collect(Collectors.toList());
        List<RekenHoofd> sleutelTussenkomsten = mainContext.getUnchecked(SLEUTEL_TUSSENKOMSTEN);
        if (sleutelTussenkomsten != null) {
            gelockten.addAll(sleutelTussenkomsten);
        }
        RekenResultatenBeheer rekenResultatenBeheer = new RekenResultatenBeheer();
        OpslaanNulResultaten saveNulResultaten = mainContext.getUnchecked(OPSLAAN_NULRESULTATEN_KEY);
        return rekenResultatenBeheer.maakRekenResultaten(mainContext, gelockten, saveNulResultaten);
    }

    protected void persisteerRekenResultaten(Admin admin, List<RekenHoofd> outputs, List<RekenHoofd> bestaanden, RekenFeedback feedback) {
        TimeLogContext.getInstance().startTimeLogging("ResultaatHandlerImp.rekenResultatenService.create");
        rekenResultatenService.create(admin, outputs);
        TimeLogContext.getInstance().endTimeLogging();
        if (feedback != null) {
            int count = (int) outputs.stream().filter(x -> x.getId() != null).count();
            feedback.setAantalRekenHoofden(count);
        }
    }

    private void checkReguls(RekenContext context, List<RekenHoofd> outputs, List<RekenHoofd> bestaanden, RegulManager regulManager) {
        Rekenmodus rekenModus = context.getUnchecked(REKENMODUS_KEY);
        Persoon persoon = context.getUnchecked(PERSOON_KEY);
        checkRegulRekenHoofden(outputs, regulManager);
        checkInhoudingZonderVergoedingen.check(persoon, rekenModus, outputs, bestaanden, regulManager);
        checkRegulRegime5(outputs, regulManager);
    }

    private void checkRegulRekenHoofden(List<RekenHoofd> outputs, RegulManager regulManager) {
        for (RekenHoofd hoofd : outputs) {
            AkeTijdperk huidigTijdperk = RekenTools.getTijdperk(hoofd.getBeginDatum());
            if (huidigTijdperk == AkeTijdperk.RSZPPO && !(hoofd.getWerkgeversCategorie() == WerkgeversCategorie.NVT
                    && hoofd.getWerknemersKengetal() == DmfapplWnkengetal.NVT)) {
                regulManager.doRegulException(hoofd.getOpdracht(), Regulkode.DMFAPPL_VOOR_2005);
            }
            for (RekenLijn lijn : hoofd.getRekenLijnen()) {
                AkeTijdperk tijdperk = AkeTijdperk.getByCode(lijn.getAardKodeExtensie().getTijdperk());
                AardKodeExt aard = AardKodeExt.getByCode(lijn.getAardKodeExtensie().getAard());
                if ((RekenTools.AARD_MET_TP_BEIDE.contains(aard) && tijdperk != AkeTijdperk.BEIDE) || (
                        RekenTools.AARD_MET_TIJDAFHANKELIJKE_TP.contains(aard) && huidigTijdperk != tijdperk)) {
                    regulManager.doRegulException(hoofd.getOpdracht(), Regulkode.TP_ONGELDIG);
                }
            }

        }
    }

    private void checkRegulRegime5(List<RekenHoofd> outputs, RegulManager regulManager) {
        for (RekenHoofd hoofd : outputs) {
            boolean regime5 = hoofd.getHoedanigheid() == Hoedanigheid.VRIJWILLIGE_BRANDWEER_ERKENTELIJKHEIDSPREMIE;
            if (regime5 && hoofd.getFiscaalJaar() >= BvTools.GRENS_FISCAAL_REGIME_5) {
                for (RekenLijn lijn : hoofd.getRekenLijnen()) {
                    LnedefRegBv regime = lijn.getRegimeBv();
                    if (regime != LnedefRegBv.VD_BV_10_BZ___VB) {
                        if (lijn.getRekenBedragen().stream()
                                .anyMatch(x -> x.getBedrag().signum() > 0 && x.getBedragType() == RekenBedragType.BRUTO_MAANDLOON)) {
                            regulManager.doRegulException(hoofd.getOpdracht(), Regulkode.ENKEL_FISCAAL_REGIME_5_TOEGELATEN);
                        }
                    }
                }
            }
        }
    }

    public void doeControles(Admin admin, RekenContext mainContext) {
        String actor = mainContext.getUnchecked(ACTOR_KEY);
        if (actor == null) {
            actor = "onbekend";
        }
        RegulManager regulManager = mainContext.getUnchecked(REGUL_MANAGER_KEY);
        TussenkomstManager tussenkomstManager = mainContext.getUnchecked(TUSSENKOMST_MANAGER_KEY);
        LoonElementManager manager = mainContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        ControlesRekenResultaten controles = new ControlesRekenResultaten(controlesRekenResultatenService, tussenkomstManager);
        RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);
        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);
        Integer fiscaalJaar = mainContext.getInteger(FISCAAL_JAAR_KEY);
        List<ControleAgenda> controleAgenda = controles.controleer(admin, persoon, rekenTijd.beginDatum, fiscaalJaar, actor);
        controleAgenda.addAll(controles.controleerBeslagOpLoonMogelijksFoutBerekend(persoon, manager, rekenTijd, actor));
        controleAgenda.addAll(controles.verwerkProtoWaarschuwingen(regulManager.getProtoWaarschuwingen(), rekenTijd, actor));
        Set<Integer> opdrachtNrs = persoon.getOpdrachten().stream().map(Opdracht::getOpdrachtnr).collect(Collectors.toSet());
        List<ControleAgenda> bestaanden =
                controleAgendaService.findOpenByPersoonIdAndDatum(admin, rekenTijd.rekenPeriode, persoon.getId(), opdrachtNrs);
        controleAgendaService.resolve(admin, bestaanden);
        if (rekenBatchNr != null) {
            controleAgenda.forEach(x -> x.setRekenBatchNr(rekenBatchNr));
        }
        controleAgendaService.create(admin, controleAgenda);
        regulManager.addWaarschuwingen(controleAgenda);

        RekenFeedback feedback = mainContext.getUnchecked(REKEN_FEEDBACK_KEY);
        if (feedback != null) {
            feedback.setAantalControleAgendas(controleAgenda.size());
        }
    }

    @Override
    public void cleanResultaten(Admin admin, RekenContext mainContext) {
        TimeLogContext.getInstance().startTimeLogging("ResultaatHandlerImp.verwerkResultaten");
        RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);
        PersoonsDataManager persoonsDataManager = mainContext.getUnchecked(PERSOONSDATA_MANAGER_KEY);
        List<RekenHoofd> bestaanden = persoonsDataManager.getBestaandeRekenResultaten(rekenTijd.beginDatum);

        for (RekenHoofd hoofd : bestaanden) {
            if (hoofd.getRnummer() == null && hoofd.getDmfapplAangifteId() == null) {
                TimeLogContext.getInstance().startTimeLogging("RekenMotorService.rekenResultatenService.delete");
                rekenResultatenService.delete(admin, hoofd);
                TimeLogContext.getInstance().endTimeLogging();
            }
        }
        TimeLogContext.getInstance().endTimeLogging();
    }

}
